#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    // Read entire input
    fseek(stdin, 0, SEEK_END);
    long len = ftell(stdin);
    fseek(stdin, 0, SEEK_SET);
    if(len<=0) return 0;
    char *buf = (char*)malloc(len+1);
    fread(buf,1,len,stdin);
    buf[len]='\0';
    // Replace literal "\\n" with actual newline
    for(char *p=buf; *p; ++p){
        if(p[0]=='\\' && p[1]=='n'){
            *p='\n';
            memmove(p+1,p+2,strlen(p+2)+1);
        }
    }
    // Tokenize by whitespace
    char *token = strtok(buf, " \t\r\n");
    if(!token) return 0;
    int T = atoi(token);
    for(int t=0; t<T; ++t){
        token = strtok(NULL, " \t\r\n");
        if(!token) break;
        int N = atoi(token);
        long long sum = 0;
        for(int i=2; i<=N; i+=2) sum += i;
        if(t==T-1)
            printf("%lld", sum);
        else
            printf("%lld\\n", sum);
    }
    free(buf);
    return 0;
}

