#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    // Read entire input
    string data((istreambuf_iterator<char>(cin)), istreambuf_iterator<char>());
    if(data.empty()) return 0;
    // Replace literal "\\n" with actual newline
    for(size_t i=0;i+1<data.size();){
        if(data[i]=='\\' && data[i+1]=='n'){
            data[i]='\n';
            data.erase(i+1,1);
        }else ++i;
    }
    // Tokenize by whitespace
    stringstream ss(data);
    int T; ss>>T;
    vector<string> out;
    for(int t=0; t<T; ++t){
        long long N; ss>>N;
        long long sum=0;
        for(long long i=2;i<=N;i+=2) sum+=i;
        out.push_back(to_string(sum));
    }
    for(size_t i=0;i<out.size();++i){
        cout<<out[i];
        if(i+1<out.size()) cout<<"\\n";
    }
    return 0;
}

